// Input: string with escaped or messy JSON
const inputString = $input.first().json.output;

function safeParse(str) {
  try {
    // Try direct parse first
    return JSON.parse(str);
  } catch (e) {
    // Try to extract JSON substring with regex
    const match = str.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (err) {
        return { error: "Failed to parse extracted JSON", raw: str };
      }
    }
    return { error: "Invalid JSON format", raw: str };
  }
}

const parsed = safeParse(inputString);

// Return cleaned output
return [
  {
    json: parsed
  }
];

// Generate prompt for AI
const workData = $input.item.json;

const prompt = `Create a casual, human-like Twitter post about my daily work. Make it authentic and relatable.

Work done: ${workData.work_description || 'Working on the project'}
Achievement: ${workData.achievement || 'Made progress'}
Challenges: ${workData.challenges || 'None mentioned'}
Tomorrow's focus: ${workData.tomorrow_focus || 'Continue building'}

Guidelines:
- Keep it under 280 characters
- Use casual tone, like talking to friends
- Include 1-2 relevant emojis naturally
- Mention specific details
- Show both wins and struggles (authentic)
- Add 2-3 relevant hashtags at the end
- NO generic motivational speak
- NO corporate jargon
- Make it feel personal and real

Generate 3 different variations separated by "---".`;

return {
  json: {
    prompt: prompt,
    original_data: workData
  }
};

// Parse AI response and extract tweet variations
const response = $input.item.json;
const content = response.content[0].text;

// Split variations by common patterns
let variations = [];

// Try multiple splitting patterns
if (content.includes('---')) {
  variations = content.split('---').map(v => v.trim()).filter(v => v.length > 0);
} else if (content.match(/\d+\./)) {
  variations = content.split(/\d+\./).map(v => v.trim()).filter(v => v.length > 0);
} else {
  // Fallback: split by double newlines
  variations = content.split('\n\n').map(v => v.trim()).filter(v => v.length > 20);
}

// Take first 3 variations
variations = variations.slice(0, 3);

// Ensure we have 3 variations
while (variations.length < 3) {
  variations.push('Generated tweet option ' + (variations.length + 1));
}

return {
  json: {
    variation_1: variations[0],
    variation_2: variations[1],
    variation_3: variations[2],
    original_data: $json.original_data || {},
    all_variations: variations
  }
};

