// Get the selected variation from callback data
const callbackData = $input.item.json.callback_query.data;

// The callback data format is: post_X|||tweet_text
const parts = callbackData.split('|||');
const selectedTweet = parts.length > 1 ? parts[1] : '';

// If empty, try to extract from message
if (!selectedTweet) {
  const message = $input.item.json.callback_query.message.text;
  const varNum = callbackData.replace('post_', '').split('|||')[0];

  // Extract the selected tweet from message
  const optionRegex = new RegExp(`\\*OPTION ${varNum}:\\*\\n([\\s\\S]*?)(?=\\n\\n\\*OPTION|━━━|$)`, 'i');
  const match = message.match(optionRegex);

  if (match) {
    return {
      json: {
        tweet_text: match[1].trim(),
        approval_time: new Date().toISOString(),
        selected_option: varNum
      }
    };
  }
}

return {
  json: {
    tweet_text: selectedTweet.trim(),
    approval_time: new Date().toISOString(),
    selected_option: callbackData.split('_')[1]
  }
};
